// Pull both ensures-forall into the proof context so triggers line up
// on `post1_self_.page_array@[i]` / `post2_self_.page_array@[i]`.
assert(forall|i: int|
    #![trigger post1_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    #![trigger post1_self_.page_array@[i].ref_count]
    #![trigger pre_self_.page_array@[i].ref_count]
    0 <= i < NUM_PAGES && i != index ==> post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
assert(forall|i: int|
    #![trigger post2_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    #![trigger post2_self_.page_array@[i].ref_count]
    #![trigger pre_self_.page_array@[i].ref_count]
    0 <= i < NUM_PAGES && i != index ==> post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);

// Pointwise: the two page_arrays agree at every index.
assert forall|i: int| 0 <= i < NUM_PAGES implies
    post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
    if i == index as int {
        // Per-field ensures pin every field of page_array@[index] in both runs
        // to the same value (the pre-state field, or the input `state` for `.state`),
        // so the two Page structs are extensionally equal field-by-field.
        assert(post1_self_.page_array@[i].addr =~= post2_self_.page_array@[i].addr);
        assert(post1_self_.page_array@[i].is_io_page =~= post2_self_.page_array@[i].is_io_page);
        assert(post1_self_.page_array@[i].rev_pointer =~= post2_self_.page_array@[i].rev_pointer);
        assert(post1_self_.page_array@[i].ref_count =~= post2_self_.page_array@[i].ref_count);
        assert(post1_self_.page_array@[i].owning_container =~= post2_self_.page_array@[i].owning_container);
        assert(post1_self_.page_array@[i].mappings =~= post2_self_.page_array@[i].mappings);
        assert(post1_self_.page_array@[i].io_mappings =~= post2_self_.page_array@[i].io_mappings);
        assert(post1_self_.page_array@[i].state =~= post2_self_.page_array@[i].state);
    } else {
        // Both equal pre_self_.page_array@[i] via the two foralls above.
    }
}

// Sequence extensionality lifts the pointwise equality to view-equality.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
